head.b:skin:
/* =========================================
   ACBPT Certificate Verification Theme
   Palette: Navy / White / Red
   Font: Tajawal
========================================= */
@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap');

:root {
  --navy: #0b1e4f;
  --navy-soft: #142a66;
  --white: #ffffff;
  --red: #c1121f;
  --gray-100: #f7f8fb;
  --gray-300: #dfe3ef;
  --gray-600: #4b556b;
  --shadow: 0 10px 30px rgba(11, 30, 79, 0.08);
  --radius: 14px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

body {
  font-family: 'Tajawal', Arial, sans-serif;
  background: var(--gray-100);
  color: var(--navy);
  line-height: 1.5;
}

a {
  color: inherit;
  text-decoration: none;
}

.app-shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.site-header {
  background: var(--white);
  border-bottom: 1px solid var(--gray-300);
  padding: 20px 16px;
}

.logo-wrap {
  display: flex;
  justify-content: center;
}

.logo-wrap img {
  width: 180px;
  max-width: 70%;
  height: auto;
}

.site-main {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px 14px;
}

.card {
  width: 100%;
  max-width: 640px;
  background: var(--white);
  border: 1px solid var(--gray-300);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 24px 18px;
}

.verify-title {
  text-align: center;
  margin: 0 0 16px;
  font-size: 1.35rem;
  font-weight: 800;
  color: var(--navy);
}

.verify-subtitle {
  text-align: center;
  margin: -8px 0 20px;
  color: var(--gray-600);
  font-size: 0.95rem;
}

.search-form {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.search-input {
  width: 100%;
  border: 1px solid var(--gray-300);
  border-radius: 10px;
  background: var(--white);
  min-height: 48px;
  padding: 0 14px;
  font-size: 1rem;
  color: var(--navy);
  outline: none;
}

.search-input:focus {
  border-color: var(--navy);
  box-shadow: 0 0 0 3px rgba(11, 30, 79, 0.12);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  border: 0;
  border-radius: 10px;
  min-height: 48px;
  padding: 0 16px;
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  transition: 0.2s ease;
}

.btn-primary {
  background: var(--navy);
  color: var(--white);
}

.btn-primary:hover {
  background: var(--navy-soft);
}

.btn-back {
  background: var(--red);
  color: var(--white);
  margin-top: 16px;
}

.btn-back:hover {
  background: #a20f1a;
}

.certificate-card {
  text-align: center;
}

.certificate-id {
  margin: 0 0 14px;
  font-size: 1.45rem;
  color: var(--navy);
  font-weight: 800;
  word-break: break-word;
}

.certificate-image {
  display: flex;
  justify-content: center;
}

.certificate-image img {
  max-width: 100%;
  width: auto;
  height: auto;
  border-radius: 10px;
  border: 1px solid var(--gray-300);
}

.no-results {
  text-align: center;
  color: var(--red);
  font-size: 1.05rem;
  font-weight: 700;
  margin: 8px 0 4px;
}

.site-footer {
  background: var(--navy);
  color: var(--white);
  text-align: center;
  padding: 18px 14px 20px;
}

.footer-copy {
  margin: 0 0 12px;
  font-size: 0.92rem;
}

.footer-socials {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 10px;
}

.social-link {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.28);
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.social-link svg {
  width: 19px;
  height: 19px;
  fill: var(--white);
}

@media (min-width: 768px) {
  .site-main {
    padding: 36px 20px;
  }

  .card {
    padding: 30px 28px;
  }

  .search-form {
    flex-direction: row;
  }

  .search-form .search-input {
    flex: 1;
  }

  .search-form .btn {
    min-width: 170px;
  }
}
